INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('9468a7f2-4a91-53f4-9b0d-5030038c7aab', 'd99f5952-91d8-41d5-8a1c-267609e39a20', 'There were ___ 100 people in the audience.', '觀眾大約有100人。', 'about', 'surely', 'quickly', 'deeply', '表示數量或時間的近似值 (大約)', 'about + [數字] → 大約的數量', '2026-07-05 07:40:09', '2026-07-05 07:40:09'),
('033925a0-6c18-5080-a77b-97bc56c3ea3f', '9ca83817-a068-4ed1-8b14-16cb7ca8f848', 'I didn''t mean to break the vase; it was just an ___.', '我不是故意打破花瓶的；那只是一個意外。', 'accident', 'opinion', 'idea', 'attempt', 'ad- (向) + cadere (落下) → 意指無法預期而「降臨」在身上的事情。', '記住 accident 是指「非預期」發生的事，就像掉下來的石頭一樣，無法事先決定。', '2026-07-06 16:47:03', '2026-07-06 16:47:03'),
('5924be71-fa27-5e52-95ab-1ee058f541db', '8c46583a-cf12-40a5-a096-777b6cfae86f', 'The class finished ten minutes ___.', '課程在十分鐘前結束了。', 'ago', 'soon', 'always', 'well', 'ago 用於表達「多久以前」，結構為「時間 + ago」。', 'a + go → 走開了 → 以前。', '2026-07-06 13:30:30', '2026-07-06 13:30:30'),
('149d9703-da70-57ec-af10-caa2047db677', '8a1102a2-57f5-42d7-a44e-63fef55785a1', 'The soldiers were caught in a sudden ___ in the dense jungle.', '士兵們在茂密的叢林中遭到突然的埋伏。', 'ambush', 'accident', 'challenge', 'victory', 'am- (在...周圍) + bush (灌木叢) → 躲在灌木叢中進行伏擊。', '躲在 bush (灌木叢) 裡面等待敵人 → ambush (埋伏)。', '2026-07-06 20:44:56', '2026-07-06 20:44:56'),
('ef126d8a-edf3-542a-8f67-a550218f5bfb', '5dd650cd-a2f8-4ae4-a55d-e815b1979fb4', 'While exploring the dusty ___ of her grandmother''s house, Sarah discovered a collection of vintage letters.', '當莎拉在祖母家佈滿灰塵的閣樓中探索時，她發現了一疊復古的信件。', 'attic', 'basement', 'balcony', 'garage', 'attic 指的是位於建築物頂部的空間。', '想像在屋頂 (top) 之下，一個用來存放舊物的空間。', '2026-07-07 02:20:43', '2026-07-07 02:20:43'),
('79f28c79-47a0-5b78-bdcc-38baceceac27', '6ba24f26-6b43-41c0-b16b-a0a3a88f8d55', 'Don''t ___ me for your mistakes.', '不要因為你的錯誤而怪罪我。', 'blame', 'thank', 'call', 'meet', 'blame 是動詞，表示將責任歸咎於某人。', '想像被責備 (blame) 時，心情會變得很「藍」(blue) 色。', '2026-07-07 03:53:18', '2026-07-07 03:53:18'),
('3237e6be-9538-57d0-a2e7-cfe9d7b37d07', '09b4a3e5-68f0-4624-a535-0dc17a69ae3f', 'The radio station will ___ the music program at 8:00 PM.', '廣播電台將會在晚上八點廣播這個音樂節目。', 'broadcast', 'perform', 'collect', 'prepare', '由 broad (廣大的) 與 cast (投擲/撒) 組成，原意是廣泛地撒播，引申為廣播或傳播訊息。', '想像把種子 broad (廣泛地) cast (丟出去) → 就像把聲音廣泛地傳播出去一樣。', '2026-07-07 08:39:49', '2026-07-07 08:39:49'),
('dbe4783e-d22d-532a-b1a5-5fa7a1b8b9d3', 'c65a0c33-e9b1-448a-98db-bb934683f81c', 'It is sunny, ___ it is very cold.', '天氣晴朗，但是非常冷。', 'but', 'and', 'so', 'or', '表示轉折 (但是)', '看到 but 就要想到轉折 (轉折 → but)', '2026-07-05 13:01:30', '2026-07-05 13:01:30'),
('bf103383-55f6-542c-a768-9eff9adbf653', '5e767169-2c20-400a-b068-5b0d10f7fd45', 'I will ___ my homework tonight.', '我今晚會做功課。', 'do', 'make', 'take', 'play', 'do (做/進行)', 'do homework → 做功課', '2026-07-05 08:35:16', '2026-07-05 08:35:16'),
('34b28d47-00ca-5f9f-bceb-60784889aec7', '28da0acf-250b-4dd3-a479-f5081a241c88', 'My little brother is only six years old, so he is in ___.', '我弟弟才六歲，所以他在讀小學。', 'elementary school', 'university', 'hospital', 'library', 'element (基本、元素) + ary (形容詞字尾) → 基本的 + school (學校)。', 'element 有「基礎」的意思，基礎的學校就是小學。', '2026-07-07 03:36:36', '2026-07-07 03:36:36'),
('1500cfa0-37b4-5764-9f88-c1593f30df53', 'f39ab957-186a-456f-ae6d-0aa238566008', 'On New Year''s ___, everyone waits for the clock to strike twelve.', '在跨年前夕，每個人都在等待時鐘敲響十二點。', 'eve', 'morning', 'afternoon', 'weekend', 'eve 指的是某個重要事件或節日發生前的那個晚上或前夕。', 'Eve 的發音與 evening (傍晚) 相似，可以聯想成節日前的一個晚上。', '2026-07-07 04:19:04', '2026-07-07 04:19:04'),
('bc39fe72-a022-5b08-9048-f75fed4ebb7b', 'f204d9c6-3815-403a-a40b-382860fdab8a', 'This clothing store is very ___ and popular.', '這間服飾店非常時尚且受歡迎。', 'fashionable', 'sleepy', 'noisy', 'brave', 'fashion (流行) + able (形容詞字尾，表示...的) → 時尚的', '想像一個 fashion show (時裝秀)，裡面的人都很 fashionable (時尚的)。', '2026-07-07 05:02:32', '2026-07-07 05:02:32'),
('21c1be9f-59dd-5de7-adfb-93dd71c03de3', '62636026-0251-407c-87f0-5f5233f0ce21', 'This song is my ___ because I listen to it every day.', '這首歌是我最喜歡的一首，因為我每天都聽。', 'favorite', 'hobby', 'dream', 'gift', 'root: favor (偏愛) + suffix: -ite (形成形容詞/名詞)', 'favor (好感) + ite → favorite (最喜愛的)', '2026-07-07 05:16:25', '2026-07-07 05:16:25'),
('07bae832-4120-5220-896e-098520344cc7', 'ad050278-a913-4be5-b0bb-d3d91b5aa55b', 'The students were told to ___ back to their classrooms after the break.', '學生們被告知在休息時間結束後要回到教室。', 'go', 'stay', 'live', 'work', 'go (v.) 表示移動或前往某處。', '想像自己正朝著目的地「走」去。', '2026-07-05 08:01:37', '2026-07-05 08:01:37'),
('8c75067c-3f44-5fbd-8035-d439752b04a3', 'aa399e16-a6c4-493c-b107-b99c7a6b4391', 'I want a cup ___ water.', '我想要一杯水。', 'of', 'at', 'in', 'on', 'of 用於表示量詞與內容物。', '一杯 + of + 水 = 一杯水', '2026-07-05 09:05:48', '2026-07-05 09:05:48'),
('1b5c80d1-8e04-53a5-9c56-0adfe6f60247', '5addd1d3-67f0-46a1-b83e-c6d01c9eb38d', 'The math problem was ___ difficult that nobody could solve it.', '這道數學題是如此困難，以至於沒人能解開它。', 'so', 'hardly', 'seldom', 'nearly', 'so 為副詞，用於 so...that 句型，表示程度之大導致某種結果。', 'so...that 是一個組合拳，so 負責程度，that 負責結果。', '2026-07-06 10:57:16', '2026-07-06 10:57:16');
